import{_ as i,c as t,o as l,a4 as o}from"./chunks/framework.C7hkbLDc.js";const d=JSON.parse('{"title":"Python更新说明","description":"","frontmatter":{},"headers":[],"relativePath":"zh/1-python/changelog.md","filePath":"zh/1-python/changelog.md"}'),a={name:"zh/1-python/changelog.md"};function _(r,e,n,s,m,p){return l(),t("div",{"data-pagefind-body":!0},e[0]||(e[0]=[o('<h1 id="python更新说明" tabindex="-1">Python 更新说明 <a class="header-anchor" href="#python更新说明" aria-label="Permalink to “Python更新说明”">​</a></h1><h2 id="1700更新2025530" tabindex="-1">1.7.0.0 更新（2025/5/30） <a class="header-anchor" href="#1700更新2025530" aria-label="Permalink to “1.7.0.0更新（2025/5/30）”">​</a></h2><ol><li><p>寄存器改动</p><ol><li>寄存器全部放在 Registers 类下，其他 Registers 后续废除</li><li>接口名改为 read_R、write_R、delete_R 类似</li><li>删除 add 方法，使用 write_XX 即可</li><li>读取和写入寄存器 RPC 接口改为新的仅读取值的 RPC，提升速度</li><li>read_R、read_MR、read_SR 直接返回对应的值和执行结果</li></ol></li><li><p>arm 类下接口改动</p><ol><li>get_arm_model_info、get_ctrl_status、get_robot_status、get_servo_status、get_soft_mode、get_version 接口改为返回 &#39; 结果 + 执行状态&#39;</li><li>servo_on、servo_off、servo_reset 接口移到 arm 下，execution 下后续废除</li></ol></li><li><p>motion 类改动</p><ol><li>paload 相关操作接口移到到 motion.payload 下</li><li>新增负载测定相关接口</li><li>新增 get_OVC、set_OVC、get_OAC、set_OAC、get_TF、set_TF、get_UF、set_UF、get_TCS、set_TCS 接口</li><li>convert_cart_to_joint_simple 接口新增 uf_index 和 tf_index 设置</li><li>新增 move_joint、move_line、move_circle 接口</li><li>新增 convert_joint_to_cart、convert_cart_to_joint 接口</li><li>新增 enter_position_control、exit_position_control、set_udp_feedback_params 接口</li></ol></li><li><p>digital_signals 类改为 signals 类，简化名称</p></li><li><p>execution 类添加 execute_bas_script 接口用于执行脚本</p></li><li><p>jogging.move 接口添加步进值修改 move (<em>self</em>, <em>aj_num</em>: <em>int</em>, <em>move_mode</em>: MoveMode = None, <em>step_length</em>: <em>float</em> = 0)</p></li><li><p>新增 bas_script 类用于生成脚本</p></li><li><p>新增 modbus 类用于直接控制 modbus 设备</p></li></ol><h2 id="1712更新202573" tabindex="-1">1.7.1.2 更新（2025/7/3） <a class="header-anchor" href="#1712更新202573" aria-label="Permalink to “1.7.1.2更新（2025/7/3）”">​</a></h2><ol><li>修复 get_all_active_alarms 接口可能发生错误的问题</li><li>修复 move_circle 内部参数设置错误</li><li>修改示例程序</li><li>添加插件管理类，提供 extension.get_robot_ip 接口</li><li>添加轨迹复现相关接口</li></ol>',5)]))}const h=i(a,[["render",_]]);export{d as __pageData,h as default};
